using System;
using System.Diagnostics;
using TextAnalysis;

// Build a consistent test corpus (~10k words)
var rng = new Random(42);
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
string text = string.Join(' ', words);
var analyzer = new TextAnalyzer(text);

// Warmup
for (int i = 0; i < 1000; i++)
{
    analyzer.AverageWordLength();
    analyzer.WordLengthHistogram();
    analyzer.UniqueWordCount();
}

const int Iterations = 100_000;
const int Rounds = 5;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Iterations per round: {Iterations:N0}  |  Rounds: {Rounds}");
Console.WriteLine(new string('-', 70));
Console.WriteLine($"{"Method",-25} {"Round",6} {"Total (ms)",12} {"Per-op (ns)",13}");
Console.WriteLine(new string('-', 70));

var methods = new (string Name, Action Fn)[]
{
    ("AverageWordLength",  () => analyzer.AverageWordLength()),
    ("WordLengthHistogram", () => analyzer.WordLengthHistogram()),
    ("UniqueWordCount",     () => analyzer.UniqueWordCount()),
};

// Collect results for summary
var medians = new Dictionary<string, List<double>>();
foreach (var m in methods) medians[m.Name] = new();

var sw = new Stopwatch();
for (int round = 1; round <= Rounds; round++)
{
    foreach (var (name, fn) in methods)
    {
        // GC before each measurement
        GC.Collect();
        GC.WaitForPendingFinalizers();
        GC.Collect();

        sw.Restart();
        for (int i = 0; i < Iterations; i++)
            fn();
        sw.Stop();

        double totalMs = sw.Elapsed.TotalMilliseconds;
        double perOpNs = totalMs / Iterations * 1_000_000;
        medians[name].Add(perOpNs);
        Console.WriteLine($"{name,-25} {round,6} {totalMs,12:F2} {perOpNs,13:F2}");
    }
}

Console.WriteLine(new string('=', 70));
