Console.WriteLine(new string('-', 40));
foreach (var (name, _) in methods)
{
    var sorted = medians[name].OrderBy(x => x).ToList();
    double median = sorted[sorted.Count / 2];
    Console.WriteLine($"{name,-25} {median,13:F2}");
}

